import*as Instance from"../instance.js";import{getKeywordName}from"../keywords.js";import*as Schema from"../schema.js";const id="https://json-schema.org/keyword/requireAllExcept",experimental=!0,compile=async(e,t,r)=>{const a=await Schema.value(e);e=getKeywordName(e.dialectId,"https://json-schema.org/keyword/properties"),e=await Schema.step(e,r);const o=Schema.typeOf(e,"object")?Schema.keys(e):[];r=new Set(o);return a.forEach(e=>o.remove(e)),[...r]},interpret=(e,t)=>!Instance.typeOf(t,"object")||e.every(e=>Object.hasOwn(Instance.value(t),e));export default{id:id,experimental:experimental,compile:compile,interpret:interpret};